#include <iostream>
#include <string>
#include <sstream>

// This function represents the correct solution, used by the driver to compare.
// The student's code would have their own implementation, possibly with errors.
long long calculateSumOfOddsCorrect(int N) {
    if (N < 1) return 0; 
    long long sum = 0;
    for (int i = 1; i <= N; i++) {
        if (i % 2 != 0) {
            sum += i;
        }
    }
    return sum;
}

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        int N;
        if (ss >> N) {
            std::cout << calculateSumOfOddsCorrect(N) << std::endl;
        }
    }
    return 0;
}
